import { describe, expect, it } from "vitest";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types";
import type { ModelMessage } from "ai";

// ============================================
// Message Interface Tests
// ============================================
describe("Message", () => {
  it("should accept valid Message with all required fields", () => {
    const modelMessage: ModelMessage = {
      id: "msg-1",
      role: "user",
      content: "Hello",
      createdAt: new Date(),
    };

    const message: Message = {
      id: "msg-1",
      createdAt: new Date(),
      modelMessage,
    };

    expect(message.id).toBe("msg-1");
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.modelMessage).toEqual(modelMessage);
  });

  it("should allow optional originalContent field", () => {
    const modelMessage: ModelMessage = {
      id: "msg-2",
      role: "assistant",
      content: "Hi there",
      createdAt: new Date(),
    };

    const messageWithOptional: Message = {
      id: "msg-2",
      createdAt: new Date(),
      modelMessage,
      originalContent: "Original text",
    };

    const messageWithoutOptional: Message = {
      id: "msg-2",
      createdAt: new Date(),
      modelMessage,
    };

    expect(messageWithOptional.originalContent).toBe("Original text");
    expect(messageWithoutOptional.originalContent).toBeUndefined();
  });

  it("should not require optional fields", () => {
    const modelMessage: ModelMessage = {
      id: "msg-3",
      role: "system",
      content: "System message",
    };

    const message: Message = {
      id: "msg-3",
      createdAt: new Date(),
      modelMessage,
    };

    // TypeScript compiles if required fields are present
    expect(message).toBeDefined();
  });
});

// ============================================
// CheckpointMessage Interface Tests
// ============================================
describe("CheckpointMessage", () => {
  it("should accept valid CheckpointMessage with all required fields", () => {
    const modelMessage: ModelMessage = {
      id: "cp-msg-1",
      role: "user",
      content: "Checkpoint content",
    };

    const checkpoint: CheckpointMessage = {
      id: "cp-123456",
      createdAt: Date.now(),
      isSummary: false,
      message: modelMessage,
    };

    expect(checkpoint.id).toBe("cp-123456");
    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.isSummary).toBe(false);
    expect(checkpoint.message).toEqual(modelMessage);
  });

  it("should allow optional originalContent field", () => {
    const modelMessage: ModelMessage = {
      id: "cp-msg-2",
      role: "assistant",
      content: "Summary",
    };

    const checkpointWithOptional: CheckpointMessage = {
      id: "cp-789",
      createdAt: Date.now(),
      isSummary: true,
      message: modelMessage,
      originalContent: "Before rewrite",
    };

    const checkpointWithoutOptional: CheckpointMessage = {
      id: "cp-789",
      createdAt: Date.now(),
      isSummary: true,
      message: modelMessage,
    };

    expect(checkpointWithOptional.originalContent).toBe("Before rewrite");
    expect(checkpointWithoutOptional.originalContent).toBeUndefined();
  });

  it("should support isSummary true for summary messages", () => {
    const modelMessage: ModelMessage = {
      id: "summary-msg",
      role: "assistant",
      content: "This is a summary",
    };

    const summaryCheckpoint: CheckpointMessage = {
      id: "summary-1",
      createdAt: Date.now(),
      isSummary: true,
      message: modelMessage,
    };

    expect(summaryCheckpoint.isSummary).toBe(true);
  });
});

// ============================================
// SessionMetadata Interface Tests
// ============================================
describe("SessionMetadata", () => {
  it("should accept valid SessionMetadata with all required fields", () => {
    const metadata: SessionMetadata = {
      sessionId: "session-123",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 100,
      completionTokens: 50,
      summaryMessageId: null,
    };

    expect(metadata.sessionId).toBe("session-123");
    expect(typeof metadata.createdAt).toBe("number");
    expect(typeof metadata.updatedAt).toBe("number");
    expect(metadata.promptTokens).toBe(100);
    expect(metadata.completionTokens).toBe(50);
    expect(metadata.summaryMessageId).toBeNull();
  });

  it("should allow summaryMessageId to be a string or null", () => {
    const withSummary: SessionMetadata = {
      sessionId: "session-456",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 200,
      completionTokens: 100,
      summaryMessageId: "summary-msg-id",
    };

    const withoutSummary: SessionMetadata = {
      sessionId: "session-789",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 50,
      completionTokens: 25,
      summaryMessageId: null,
    };

    expect(withSummary.summaryMessageId).toBe("summary-msg-id");
    expect(withoutSummary.summaryMessageId).toBeNull();
  });

  it("should represent no compaction state with null summaryMessageId", () => {
    const noCompaction: SessionMetadata = {
      sessionId: "new-session",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 0,
      completionTokens: 0,
      summaryMessageId: null,
    };

    expect(noCompaction.summaryMessageId).toBeNull();
  });
});

// ============================================
// CompactionConfig Interface Tests
// ============================================
describe("CompactionConfig", () => {
  it("should accept empty config (all fields optional)", () => {
    const emptyConfig: CompactionConfig = {};
    expect(emptyConfig).toBeDefined();
  });

  it("should accept partial config with some optional fields", () => {
    const partialConfig: CompactionConfig = {
      enabled: true,
      maxTokens: 10000,
    };

    expect(partialConfig.enabled).toBe(true);
    expect(partialConfig.maxTokens).toBe(10000);
  });

  it("should accept full config with all fields", () => {
    const summarizeFn = async (msgs: ModelMessage[], prev?: string) => {
      return "Summary";
    };

    const fullConfig: CompactionConfig = {
      contextLimit: 128000,
      enabled: true,
      keepRecentTokens: 3000,
      maxTokens: 10000,
      reserveTokens: 2500,
      speculativeStartRatio: 0.8,
      summarizeFn,
      thresholdRatio: 0.6,
    };

    expect(fullConfig.contextLimit).toBe(128000);
    expect(fullConfig.enabled).toBe(true);
    expect(fullConfig.keepRecentTokens).toBe(3000);
    expect(fullConfig.maxTokens).toBe(10000);
    expect(fullConfig.reserveTokens).toBe(2500);
    expect(fullConfig.speculativeStartRatio).toBe(0.8);
    expect(typeof fullConfig.summarizeFn).toBe("function");
    expect(fullConfig.thresholdRatio).toBe(0.6);
  });

  it("should validate contextLimit as number (0 for unlimited)", () => {
    const unlimitedConfig: CompactionConfig = {
      contextLimit: 0,
    };

    const limitedConfig: CompactionConfig = {
      contextLimit: 128000,
    };

    expect(unlimitedConfig.contextLimit).toBe(0);
    expect(limitedConfig.contextLimit).toBe(128000);
  });

  it("should validate enabled defaults to false per JSDoc", () => {
    const config: CompactionConfig = {};
    // Per JSDoc: @default false
    expect(config.enabled).toBeUndefined(); // actually undefined when not set
  });

  it("should validate keepRecentTokens defaults to 2000 per JSDoc", () => {
    const config: CompactionConfig = {};
    // Per JSDoc: @default 2000
    expect(config.keepRecentTokens).toBeUndefined(); // actually undefined when not set
  });

  it("should validate maxTokens defaults to 8000 per JSDoc", () => {
    const config: CompactionConfig = {};
    // Per JSDoc: @default 8000
    expect(config.maxTokens).toBeUndefined(); // actually undefined when not set
  });

  it("should validate reserveTokens defaults to 2000 per JSDoc", () => {
    const config: CompactionConfig = {};
    // Per JSDoc: @default 2000
    expect(config.reserveTokens).toBeUndefined(); // actually undefined when not set
  });

  it("should validate thresholdRatio defaults to 0.5 per JSDoc", () => {
    const config: CompactionConfig = {};
    // Per JSDoc: @default 0.5
    expect(config.thresholdRatio).toBeUndefined(); // actually undefined when not set
  });

  it("should accept summarizeFn callback", async () => {
    const summarizeFn = async (messages: ModelMessage[], previousSummary?: string) => {
      if (previousSummary) {
        return `${previousSummary}\nExtended summary`;
      }
      return `Summary of ${messages.length} messages`;
    };

    const config: CompactionConfig = {
      summarizeFn,
    };

    expect(typeof config.summarizeFn).toBe("function");
    if (config.summarizeFn) {
      const result = await config.summarizeFn([], "prev");
      expect(result).toContain("Extended summary");
    }
  });

  it("should validate speculativeStartRatio range hint (0.15 to 0.95)", () => {
    const config: CompactionConfig = {
      speculativeStartRatio: 0.5,
    };
    // JSDoc says valid range is 0.15 to 0.95, but runtime validation is needed
    expect(config.speculativeStartRatio).toBe(0.5);
  });
});

// ============================================
// PruningConfig Interface Tests
// ============================================
describe("PruningConfig", () => {
  it("should accept empty config (all fields optional)", () => {
    const emptyConfig: PruningConfig = {};
    expect(emptyConfig).toBeDefined();
  });

  it("should accept partial config with some optional fields", () => {
    const partialConfig: PruningConfig = {
      enabled: true,
      protectedToolNames: ["read", "write"],
    };

    expect(partialConfig.enabled).toBe(true);
    expect(partialConfig.protectedToolNames).toEqual(["read", "write"]);
  });

  it("should accept full config with all fields", () => {
    const fullConfig: PruningConfig = {
      enabled: true,
      minSavingsTokens: 300,
      protectedToolNames: ["read", "write", "execute"],
      protectRecentTokens: 3000,
      replacementText: "[removed for brevity]",
    };

    expect(fullConfig.enabled).toBe(true);
    expect(fullConfig.minSavingsTokens).toBe(300);
    expect(fullConfig.protectedToolNames).toHaveLength(3);
    expect(fullConfig.protectRecentTokens).toBe(3000);
    expect(fullConfig.replacementText).toBe("[removed for brevity]");
  });

  it("should validate enabled defaults to false per JSDoc", () => {
    const config: PruningConfig = {};
    // Per JSDoc: default: false
    expect(config.enabled).toBeUndefined();
  });

  it("should validate minSavingsTokens defaults to 200 per JSDoc", () => {
    const config: PruningConfig = {};
    // Per JSDoc: default: 200
    expect(config.minSavingsTokens).toBeUndefined();
  });

  it("should validate protectRecentTokens defaults to 2000 per JSDoc", () => {
    const config: PruningConfig = {};
    // Per JSDoc: default: 2000
    expect(config.protectRecentTokens).toBeUndefined();
  });

  it("should validate replacementText defaults to string per JSDoc", () => {
    const config: PruningConfig = {};
    // Per JSDoc: default: "[output pruned — too large]"
    expect(config.replacementText).toBeUndefined();
  });
});

// ============================================
// ContinuationVariant Type Tests
// ============================================
describe("ContinuationVariant", () => {
  it("should accept all valid variant values", () => {
    const manual: ContinuationVariant = "manual";
    const autoWithReplay: ContinuationVariant = "auto-with-replay";
    const toolLoop: ContinuationVariant = "tool-loop";

    expect(manual).toBe("manual");
    expect(autoWithReplay).toBe("auto-with-replay");
    expect(toolLoop).toBe("tool-loop");
  });

  it("should be assignable to string", () => {
    const variant: ContinuationVariant = "manual";
    const str: string = variant;
    expect(str).toBe("manual");
  });
});

// ============================================
// CompactionResult Interface Tests
// ============================================
describe("CompactionResult", () => {
  it("should accept valid CompactionResult with required fields only", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 10000,
      tokensAfter: 5000,
    };

    expect(result.success).toBe(true);
    expect(result.tokensBefore).toBe(10000);
    expect(result.tokensAfter).toBe(5000);
  });

  it("should allow all optional fields", () => {
    const result: CompactionResult = {
      success: false,
      tokensBefore: 10000,
      tokensAfter: 10000,
      reason: "Context too large",
      summaryMessageId: "summary-1",
      continuationVariant: "auto-with-replay",
    };

    expect(result.success).toBe(false);
    expect(result.reason).toBe("Context too large");
    expect(result.summaryMessageId).toBe("summary-1");
    expect(result.continuationVariant).toBe("auto-with-replay");
  });

  it("should support success true with summaryMessageId", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 15000,
      tokensAfter: 3000,
      summaryMessageId: "summary-msg",
    };

    expect(result.success).toBe(true);
    expect(result.summaryMessageId).toBe("summary-msg");
  });

  it("should support success false with reason", () => {
    const result: CompactionResult = {
      success: false,
      tokensBefore: 1000,
      tokensAfter: 1000,
      reason: "Summarization failed",
    };

    expect(result.success).toBe(false);
    expect(result.reason).toBe("Summarization failed");
  });

  it("should support all continuation variants", () => {
    const withManual: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      continuationVariant: "manual",
    };

    const withAutoReplay: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      continuationVariant: "auto-with-replay",
    };

    const withToolLoop: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      continuationVariant: "tool-loop",
